package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetNullStringDefaultNull() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertNull(format.getNullString());
    }

    @Test
    void testGetNullStringSetValue() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        assertEquals("NULL", format.getNullString());
    }

    @Test
    void testGetNullStringEmptyString() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("");
        assertEquals("", format.getNullString());
    }

    @Test
    void testGetNullStringBackslashN() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("\\N");
        assertEquals("\\N", format.getNullString());
    }

    @Test
    void testGetNullStringWithPredefinedMYSQL() {
        CSVFormat format = CSVFormat.MYSQL;
        assertEquals("\\N", format.getNullString());
    }

    @Test
    void testGetNullStringWithPredefinedPOSTGRESQL_CSV() {
        CSVFormat format = CSVFormat.POSTGRESQL_CSV;
        assertEquals("", format.getNullString());
    }

    @Test
    void testGetNullStringWithPredefinedPOSTGRESQL_TEXT() {
        CSVFormat format = CSVFormat.POSTGRESQL_TEXT;
        assertEquals("\\N", format.getNullString());
    }
}
